library(haven); library(dplyr); library(purrr); library(labelled); library(readr)
dir.create("data/output", showWarnings = FALSE, recursive = TRUE)
w1 <- read_delim("data/input/wave_one_lsype_family_background_2020.tab", delim = "\t", show_col_types = FALSE)
w2 <- read_delim("data/input/wave_two_lsype_family_background_2020.tab", delim = "\t", show_col_types = FALSE)
w4 <- read_delim("data/input/wave_four_lsype_family_background_2020.tab", delim = "\t", show_col_types = FALSE)
w1_sel <- w1 %>% select(NSID, W1hiqualmum, W1hiqualdad)
w2_sel <- w2 %>% select(NSID, W2hiqualmum, W2hiqualdad)
w4_sel <- w4 %>% select(NSID, w4hiqualmum, w4hiqualdad)
merged <- w1_sel %>% full_join(w2_sel, by = "NSID") %>% full_join(w4_sel, by = "NSID")
harmonize_missing <- function(x, wave) { x[is.na(x)] <- -3; if (wave %in% c(1,2)) { x[x == -999] <- -2; x[x == -99] <- -3; x[x == -98] <- -3; x[x == -94] <- -8; x[x == -92] <- -9; x[x == -91] <- -1; x[x == -1] <- -8 } else if (wave == 4) { x[x == -99] <- -3; x[x == -98] <- -3; x[x == -94] <- -8 }; return(x) }
merged <- merged %>% mutate(W1hiqualmum = harmonize_missing(W1hiqualmum, 1), W1hiqualdad = harmonize_missing(W1hiqualdad, 1), W2hiqualmum = harmonize_missing(W2hiqualmum, 2), W2hiqualdad = harmonize_missing(W2hiqualdad, 2), w4hiqualmum = harmonize_missing(w4hiqualmum, 4), w4hiqualdad = harmonize_missing(w4hiqualdad, 4))
consolidate_educ <- function(a, b, c) { if (!is.na(a) && a >= 1 && a <= 20) return(a); if (!is.na(b) && b >= 1 && b <= 20) return(b); if (!is.na(c) && c >= 1 && c <= 20) return(c); if (!is.na(a)) return(a); if (!is.na(b)) return(b); if (!is.na(c)) return(c); return(-3) }
merged <- merged %>% rowwise() %>% mutate(educdtlma = consolidate_educ(W1hiqualmum, W2hiqualmum, w4hiqualmum), educdtlpa = consolidate_educ(W1hiqualdad, W2hiqualdad, w4hiqualdad)) %>% ungroup()
collapse_educ <- function(x) { r <- x; r[x >= 1 & x <= 4] <- 0; r[x >= 5 & x <= 17] <- 1; r[x == 18] <- 2; r[x == 19] <- 3; r[x == 20] <- 4; return(r) }
merged <- merged %>% mutate(educma = collapse_educ(educdtlma), educpa = collapse_educ(educdtlpa))
dl <- c(Higher_Degree=1, First_Degree=2, HE_Diploma=3, HNC_HND_NVQ4=4, Teaching_qual=5, Nursing_qual=6, A_Levels=7, OND_ONC=8, City_guilds_NVQ3=9, CSYS=10, Scottish_Higher=11, AS_Level=12, Trade_apprenticeship=13, City_guilds_NVQ2=14, GCSE_A_C=15, GCSE_D_E=16, City_guilds_NVQ1=17, Youth_training=18, Qual_unspecified=19, No_qual=20, Not_applicable=-1, Info_lost=-2, Not_asked=-3, Dont_know=-8, Refusal=-9)
cl <- c(NVQ_4_5=0, NVQ_1_3=1, None_entry=2, Other=3, No_qual=4, Not_applicable=-1, Info_lost=-2, Not_asked=-3, Dont_know=-8, Refusal=-9)
merged <- merged %>% mutate(educdtlma = labelled(educdtlma, labels = dl), educdtlpa = labelled(educdtlpa, labels = dl), educma = labelled(educma, labels = cl), educpa = labelled(educpa, labels = cl))
final_data <- merged %>% select(NSID, educma, educpa, educdtlma, educdtlpa)
write_csv(final_data, "data/output/cleaned_data.csv")
cat("Done. Rows:", nrow(final_data), "\n")